import{_ as e,W as t,X as a,$ as d}from"./framework-586fce15.js";const o={},i=d(`<ul><li><a href="#1-logging">1. logging</a><ul><li><a href="#11-introduction">1.1. Introduction</a></li><li><a href="#12-configurate-logs">1.2. Configurate logs</a><ul><li><a href="#121-rule">1.2.1. Rule</a></li></ul></li><li><a href="#13-clean-logs">1.3. Clean logs</a><ul><li><a href="#131-automatical">1.3.1. Automatical</a></li><li><a href="#132-handy">1.3.2. Handy</a></li></ul></li><li><a href="#14-disable-logging">1.4. Disable logging</a></li></ul></li></ul><hr><h1 id="_1-logging" tabindex="-1"><a class="header-anchor" href="#_1-logging" aria-hidden="true">#</a> 1. logging</h1><h2 id="_1-1-introduction" tabindex="-1"><a class="header-anchor" href="#_1-1-introduction" aria-hidden="true">#</a> 1.1. Introduction</h2><p>Linux uses a daemon called <code>syslogd</code> to automatically log events on your computer. Several variations of <code>syslog</code>, including <code>rsyslog</code> and <code>syslog-ng</code>.</p><p>Debian comes with <code>rsyslog</code> by default.</p><h2 id="_1-2-configurate-logs" tabindex="-1"><a class="header-anchor" href="#_1-2-configurate-logs" aria-hidden="true">#</a> 1.2. Configurate logs</h2><p>The <code>rsyslog</code> configuration file is located at <code>/etc/rsyslog.conf</code>.</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ <span class="token function">vim</span> /etc/rsyslog.conf
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="_1-2-1-rule" tabindex="-1"><a class="header-anchor" href="#_1-2-1-rule" aria-hidden="true">#</a> 1.2.1. Rule</h3><p>Navigate down to below line 50, you’ll find the <strong>Rule</strong> ssection. This is about system automatical log.</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>auth,authpriv.*     /var/log/auth.log
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>The Syntax is <code>facility.priority action</code>.</p><ul><li>facility the program, such as <code>mail</code>, <code>kernel</code>, or <code>lpr</code>.</li><li>priority what kind of messages to log for that program.</li><li>action the location where the log will be sent. Generally, log files are sent to the <code>/var/log</code> directory</li></ul><table><thead><tr><th>facility</th><th>function</th></tr></thead><tbody><tr><td>auth/authpriv</td><td>Security/authorization messages</td></tr><tr><td>cron</td><td>Clock daemons</td></tr><tr><td>daemon</td><td>Other daemons</td></tr><tr><td>kern</td><td>Kernel messages</td></tr><tr><td>lpr</td><td>Printing system</td></tr><tr><td>mail</td><td>Mail system</td></tr><tr><td>user</td><td>Generic user­level messages</td></tr><tr><td><code>*</code></td><td>refers to all facilities</td></tr><tr><td><code>facility1,facility2</code></td><td>You can select more than one facility by listing them separated by a comma</td></tr></tbody></table><table><thead><tr><th>priority</th><th>level</th><th>should deprecate(√)</th></tr></thead><tbody><tr><td>debug</td><td>lowest prioriy</td><td>still use</td></tr><tr><td>info</td><td></td><td>still use</td></tr><tr><td>notice</td><td></td><td>still use</td></tr><tr><td>warning</td><td></td><td>√</td></tr><tr><td>warn</td><td></td><td>√</td></tr><tr><td>error</td><td></td><td>√</td></tr><tr><td>err</td><td></td><td>√</td></tr><tr><td>crit</td><td></td><td>still use</td></tr><tr><td>alert</td><td></td><td>still use</td></tr><tr><td>emerg</td><td></td><td>√</td></tr><tr><td>panic</td><td>highest priority</td><td>√</td></tr><tr><td><code>*</code></td><td>all priorities are logged</td><td></td></tr></tbody></table><p>When you specify a priority, messages of that priority and higher are logged.</p><h2 id="_1-3-clean-logs" tabindex="-1"><a class="header-anchor" href="#_1-3-clean-logs" aria-hidden="true">#</a> 1.3. Clean logs</h2><h3 id="_1-3-1-automatical" tabindex="-1"><a class="header-anchor" href="#_1-3-1-automatical" aria-hidden="true">#</a> 1.3.1. Automatical</h3><p><code>logrotate</code>(Log rotation) is the process of regularly archiving log files by moving them to some other location, leaving you with a fresh log file. That archived location will then get cleaned up after a specified period of time.</p><p>You can configure the <code>logrotate</code> utility to choose the regularity of your log rotation with the <code>/etc/logrotate.conf</code>.</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ <span class="token function">vim</span> /etc/logrotate.conf
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>At the end of each rotation period, the log files are <strong>renamed</strong> and <strong>pushed toward</strong> the end of the chain of logs as a new log file is created, replacing the current log file.</p><ul><li>rename: <code>/var/log.auth</code> will become <code>/var/log.auth.1</code>, then <code>/var/log.auth.2</code>, and so on.</li><li>push forward If you rotate logs every four weeks and keep four set of backups, <code>/var/log.auth.3</code> become <code>/var/log.auth.4</code>, but <code>/var/log.auth.4</code> will be <strong>deleted</strong> rather than being pushed to <code>/var/log/auth.5</code>.</li></ul><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ <span class="token function">locate</span> /var/log/auth.log.*
/var/log/auth.log.1 
/var/log/auth.log.2 
/var/log/auth.log.3 
/var/log/auth.log.4
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_1-3-2-handy" tabindex="-1"><a class="header-anchor" href="#_1-3-2-handy" aria-hidden="true">#</a> 1.3.2. Handy</h3><p>Easily deleted files can generally be recovered by a skilled forensic investigator.</p><p>Advanced way is firstly overwrite the file several times before deletion.</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ shred FILE
$ shred <span class="token parameter variable">-f</span> <span class="token parameter variable">-n</span> <span class="token number">10</span> /var/log/auth.log.*
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><code>shred</code> options:</p><ul><li>overwrite times By default, shred overwrites 4 times. <code>-n NUM</code>, lets you choose how many times to overwrite the files.</li><li>permission changes the permissions on the files to allow overwriting if a permission change is necessary</li></ul><p>Now, when you see the content of the file, it is full of shit.</p><h2 id="_1-4-disable-logging" tabindex="-1"><a class="header-anchor" href="#_1-4-disable-logging" aria-hidden="true">#</a> 1.4. Disable logging</h2><p>When a hacker takes control of a system, they could immediately disable logging to prevent the system from keeping track of their activities.</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ <span class="token operator">&gt;</span>service rsyslog stop
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div>`,35),r=[i];function l(s,n){return t(),a("div",null,r)}const h=e(o,[["render",l],["__file","logging.html.vue"]]);export{h as default};
